import { mkdir, readFile, writeFile } from 'node:fs/promises'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

const __filename = fileURLToPath(import.meta.url)
const __dirname = path.dirname(__filename)

const sourcePath = path.resolve(__dirname, '../../../packages/rag-ai/system-prompt.md')
const targetPath = path.resolve(__dirname, '../src/aisearch/system-prompt.ts')

async function main() {
  const source = await readFile(sourcePath, 'utf8')
  const generated = [
    '// This file is auto-generated by `npm run sync-system-prompt`.',
    `// Source: ${toPosixRelativePath(path.resolve(__dirname, '..'), sourcePath)}`,
    '',
    `const systemPrompt = ${JSON.stringify(source)}`,
    '',
    'export default systemPrompt',
    ''
  ].join('\n')

  await mkdir(path.dirname(targetPath), { recursive: true })
  await writeFile(targetPath, generated, 'utf8')

  console.log('[main-api] Synced AI Search system prompt', {
    source: sourcePath,
    target: targetPath
  })
}

function toPosixRelativePath(fromPath, toPath) {
  return path.relative(fromPath, toPath).split(path.sep).join('/')
}

main().catch((error) => {
  console.error('[main-api] Failed to sync AI Search system prompt', error)
  process.exitCode = 1
})
